(1, 16, 397, 'Wilshire', 'Calcee celvit', 'NANA', '10', 13.71, 'Calcee celvit is used to support bone strength and calcium levels with added vitamin D – Use as per your doctor’s recommendation.', 'Yes', 'Yes', 'Pending', '', 'Medical', 'FALSE', 0, '', '', '0', '0', 'یلوٹ', '', '', '', 0, 0.00, '1', '4/9/2024', 0, 'U', 108, '', '0', '0', '0', '-16', '0', '0', '', 'Calcee celvit.webp'),
(2, 16, 1279, 'Reckitt Benckiser', 'Sani plast', 'NA', '2.97', 4.00, 'Sani plast is a basic first-aid bandage used for covering minor cuts and wounds to protect from infection – Use as per your doctor’s recommendation.', 'Yes', 'Yes', 'Pending', '', 'Medical', 'FALSE', 0, '', '', '0', '0', 'سنی پلاسٹ', '', '', '', 0, 0.00, '1', '12/15/2020', 362, 'U', 691, '', '0', '0', '0', '880', '0', '0', '', 'Sani plast.jfif'),
(3, 16, 1317, 'Qarshi', 'Arq-e-Shireen', 'NA', '100', 120.00, 'Arq-e-Shireen is a traditional herbal tonic used to aid digestion and improve general vitality – Use as per your doctor’s recommendation.', 'Yes', 'Yes', 'Pending', '', 'Medical', 'FALSE', 0, '', '', '0', '0', 'Arq-e-Shireen', '', '', '', 0, 0.00, '1', '2/10/2019', 0, 'U', 709, '', '0', '0', '0', '11', '0', '0', '', 'Arq-e-Shireen.webp'),
