(5, 16, 1320, 'unani', 'Gripe Water', 'NA', '98', 125.00, 'Gripe Water helps relieve colic, gas, and stomach discomfort in infants – Use as per your doctor’s recommendation.', 'No', 'Yes', 'Pending', '', 'Medical', 'FALSE', 0, '', '', '0', '0', 'گرائپ واٹر', '', '', '', 0, 0.00, '1', '12/15/2020', -1, 'U', 711, '', '0', '0', '0', '10', '0', '0', '', 'Gripe Water.jpg'),
