(14, 19, 3725, 'Milk TINN', 'Meiji Fmt 1 400G', '', '2222.84', 2450.00, 'Meiji FMT 1 Tin 400g is an infant formula suited for babies from birth up to 6 months. It’s fortified with DHA for brain and eye development, omega‑3 & omega‑6 fatty acids, milk phospholipids, nucleotides, FOS (prebiotic fibers), taurine, and essential vitamins and minerals to support growth and immunity . Use on your pediatrician’s advice.', 'Yes', 'Yes', 'Pending', '', 'Medical', 'FALSE', 0, '', '', '0', '0', 'میجی ایف ایم ٹی 1 400G', '', '', '', 0, 0.00, '1', '12/15/2020', 0, 'U', 2281, '', '0', '0', '0', '0', '0', '0', '', 'Meiji Fmt 1 400G.png'),
(15, 19, 3726, 'Milk TINN', 'Meiji Fu 2 400G', '', '2109.3', 2350.00, 'Meiji FU-2 400g is a follow-up formula designed for babies aged 6 to 12 months. It provides balanced nutrition with essential vitamins, minerals, DHA, and iron to support healthy growth, brain development, and a strong immune system during the weaning stage.\r\n\r\nHow to Use:\r\nMix the recommended amount of powder with boiled, lukewarm water according to the instructions on the tin. Use a sterilized bottle or cup and feed immediately.\r\n\r\nNote:\r\nUse only under the advice of a doctor or pediatrician. Breastfeeding is recommended wherever possible.', 'Yes', 'Yes', 'Pending', '', 'Medical', 'FALSE', 0, '', '', '0', '0', 'میجی ایف یو 2 400G', '', '', '', 0, 0.00, '1', '2/10/2019', 0, 'U', 2282, '', '0', '0', '0', '0', '0', '0', '', 'Meiji Fu 2 400G.jpg'),
(16, 19, 3728, 'Milk TINN', 'Meiji Pre 400G', '', '1641.83', 1800.00, 'Meiji Pre 400g is a formula for preterm or low birth weight babies. It supports growth, digestion, and immunity with nutrients like DHA, prebiotics, and essential vitamins. Use under doctor’s supervision.', 'No', 'Yes', 'Pending', '', 'Medical', 'FALSE', 0, '', '', '0', '0', 'میجی پرے 400G', '', '', '', 0, 0.00, '1', '2/10/2019', 0, 'U', 2283, '', '0', '0', '0', '0', '0', '0', '', 'Meiji Pre 400G.png'),
(17, 20, 3729, 'Milk TINN', 'Meiji Big 3 400G', '', '2222.84', 2300.00, 'Meiji Big 3 400 g is a growing‑up formula designed for toddlers aged 1 year and above, offering balanced nutrition for healthy development. It contains 40% whey protein, added sulfur amino acids, DHA, milk phospholipids, omega‑3 & omega‑6 fatty acids, and FOS prebiotics to support brain, retinal, and gut health . Use as part of a varied diet, under pediatric guidance.', 'Yes', 'Yes', 'Pending', '', 'Medical', 'FALSE', 0, '', '', '0', '0', 'میجی بگ 3 400g', '', '', '', 0, 0.00, '1', '2/10/2019', 0, 'U', 2284, '', '0', '0', '0', '1', '0', '0', '', 'Meiji Big 3 400G.webp'),
(18, 20, 3730, 'Milk TINN', 'Meiji Lactoless 350G', '', '2222.88', 2350.00, 'Meiji Lactoless 350 g is a lactose‑free infant and children’s formula designed for those with lactase deficiency, galactosemia, or transient lactose intolerance. Featuring easily digestible milk proteins, it’s fortified with taurine and cystine, balanced essential fatty acids (linoleic & α‑linolenic), minerals, vitamins (A, B, C, D, E, K), calcium, vitamin D, and iron—helping support growth while minimizing gastrointestinal discomfort. Use under pediatric guidance.', 'Yes', 'Yes', 'Pending', '', 'Medical', 'FALSE', 0, '', '', '0', '0', 'میجی لیکٹولیس 350G', '', '', '', 0, 0.00, '1', '2/10/2019', 0, 'U', 2285, '', '0', '0', '0', '1', '0', '0', '', 'Meiji Lactoless 350G.png'),
(19, 19, 3731, 'Milk TINN', 'Meiji mamilac 350G', '', '1851.3', 2300.00, 'Meiji Mamilac 350 g is a sucrose-free milk powder formulated for pregnant and breastfeeding women, also suitable for toddlers. It supports brain and eye development with DHA, prevents neural tube defects with folic acid, and aids immunity and bone health with added iron, calcium, zinc, FOS prebiotics, β‑carotene, and vitamin K . Use as part of a balanced diet under a doctor’s advice.', 'Yes', 'Yes', '', '', 'Medical', 'FALSE', 0, '', '', '0', '0', 'میجی مامیلیک 350G', '', '', '', 0, 0.00, '1', '2/10/2019', 0, 'U', 2286, '', '0', '0', '0', '1', '0', '0', '', 'Meiji mamilac 350G.png'),
(20, 19, 3758, 'Milk TINN', 'Cow and Gate almiron 400G', '', '2573.91', 2800.00, 'Lactose-free infant formula from birth. Supports digestion, growth, and immunity. For lactose intolerance or diarrhea.', 'Yes', 'Yes', 'Pending', '', 'Medical', 'FALSE', 0, '', '', '0', '0', 'کاؤ ان گیٹ  المیرون 400G', '', '', '', 0, 0.00, '1', '12/15/2020', 0, 'U', 2307, '', '0', '0', '0', '-1', '0', '0', '', 'Cow&gate almiron 400G.webp'),
