(26, 18, 9458, 'Pharmevo', 'Avsar 160/5mg', '', '29.99', 35.29, 'Avsar 160/5 mg is a prescription medicine that combines Valsartan (160 mg) and Amlodipine (5 mg). It is used to effectively manage high blood pressure (hypertension) and helps reduce the risk of heart attacks and strokes.\r\n\r\nHow to Use:\r\nTake the tablet once daily with or without food, at the same time each day, or as directed by your doctor. Do not skip or exceed the prescribed dose.\r\n\r\nNote:\r\nThis medicine should only be used under the recommendation and supervision of a qualified healthcare professional.', 'No', 'Yes', 'Pending', '', 'Medical', 'FALSE', 0, '', '', '0', '0', 'Avsar 160/5mg', '', '', '', 0, 0.00, '1', '12/15/2020', 0, 'U', 7163, '', '0', '0', '0', '3', '0', '0', '', 'avsar-5-by-160mg.jpg'),
(27, 18, 9459, 'Pharmevo', 'Avsar 160/10mg', '', '35.7', 42.86, 'Avsar 160/10 mg contains Valsartan (160 mg) and Amlodipine (10 mg), used to treat high blood pressure (hypertension). It helps relax blood vessels, improving blood flow and reducing the risk of heart-related complications like strokes or heart attacks.\r\n\r\nHow to Use:\r\nTake one tablet daily with or without food, preferably at the same time each day. Follow your doctor’s instructions carefully.\r\n\r\nNote:\r\nUse only on the advice and prescription of a qualified healthcare professional.', '', 'Yes', '', '', 'Medical', 'FALSE', 0, '', '', '0', '0', 'Avsar 160/10mg', '', '', '', 0, 0.00, '1', '12/15/2020', 0, 'U', 7164, '', '0', '0', '0', '3', '0', '0', '', 'avsar-160-by-10md.jpg'),
