(9046, 19, 27770, 'MILK', 'BF Mama Soft Pack 200gm', '', '805', 950.00, 'BF Mama Soft Pack 200gm is a specially formulated nutritional supplement for pregnant and breastfeeding mothers. It provides essential nutrients such as folic acid, iron, calcium, DHA, and vitamins to support the health of both mother and baby during and after pregnancy.\r\n<br>\r\nHow to Use:\r\nMix the recommended number of scoops with lukewarm, previously boiled water or milk as per the instructions on the pack. Stir well and consume immediately.\r\n\r\nNote:\r\nUse only as advised by a doctor or healthcare provider. This product is a supplement and should not replace a balanced diet.', 'Yes', 'Yes', 'Pending', '', '', 'FALSE', 0, '', '', '0', '0', '', '', '', '', 0, 0.00, '1', '4/22/2024', 0, 'U', 26431, '', '', '', '', '', '', '', '', 'BF Mama Soft Pack 200gm.jpg'),
(9047, 20, 27772, 'morinaga', 'BF Grow 3 Soft Pack 300gm', '', '1119.43', 1250.00, 'BF Grow 3 Soft Pack 300gm is a nutritious growing-up formula for children aged 1 to 3 years. Packed with vital nutrients including DHA, calcium, iron, and vitamins, it supports healthy physical development, brain function, and immune strength during early childhood.\r\n\r\nHow to Use:\r\nDissolve the recommended number of scoops in previously boiled, lukewarm water as per the instructions on the pack. Serve fresh in a clean bottle or cup.\r\n\r\nNote:\r\nShould be used only under the supervision of a healthcare professional. Not a replacement for breastfeeding, but a supplement for toddlers’ daily nutrition.\r\n\r\n', 'Yes', 'Yes', 'Pending', '', '', 'FALSE', 0, '', '', '0', '0', '', '', '', '', 0, 0.00, '1', '4/25/2024', 0, 'U', 26433, '', '', '', '', '', '', '', '', 'Grow 3 Soft Pack 300gm.jpg'),
